var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"회동에서 그런 이야기가 오갔군요…… 저는 까맣게 몰랐어요.","JPN":"会合でそんなことがあったんですね……まったく知りませんでした。","ENG":"So that's what happened at the meeting. I had no idea.","TWN":"原來會議上談到了那樣的話題啊……我完全不知道。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 이제야 기억이 나네요.","JPN":"そうでした。やっと思い出しましたわ。","ENG":"Yes. I remember now.","TWN":"是啊，我現在才想起來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 날 이후로 너무 분해서 며칠 동안 식사도 제대로 못 했어요.","JPN":"あの日以来、あまりの悔しさに何日も食事が喉を通りませんでしたわ。","ENG":"I was furious that I could not eat for days.","TWN":"那天之後，我因為太生氣了，好幾天都沒好好吃飯。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"다들 놀랐을 거야. 보통은 학회장직을 승계했다고 공표하는 자리를 예상했거든.","JPN":"みんなびっくりしたはずよ。通常なら学会長職を引き継ぐって公表する場だもの。","ENG":"Everyone might be surprised. They all expected that meeting to be where you declared the position of President.","TWN":"大家應該都嚇到了。因為大部人都猜你會宣佈繼承學會長一職。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"설마 진심으로 정론을 들이밀 거라곤 아무도 예상 못했을걸?","JPN":"まさか本気で正論をつきつけるなんて、誰も予想していなかったわよ。","ENG":"I bet none of them thought that it would be about what the truth is or not.","TWN":"誰也沒想到你會真心地提出正確的主張？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사람이 음험한 미치광이들 앞에서 공개 망신당한 걸 웃으면서 말하지 말아 주세요.","JPN":"人が公の場で陰険な狂人たちを前に恥をかいたこと、笑いながら話さないでください。","ENG":"Please do not laugh as you discuss my humiliation in front of those crazed lunatics.","TWN":"請不要笑著說出別人在陰險的瘋子面前公開丟臉的事。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 결국 망신당한 게 부끄러운 나머지 기억에서 지워 버렸다는 건가?","JPN":"つまり、恥をかいたことが恥ずかしくて記憶から消してしまったということかい？","ENG":"So you buried that memory out of humiliation?","TWN":"那說到底，你是因為太丟臉，覺得不好意思，才在記憶中抹除的嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 전 그렇게 치졸한 사람이 아닙니다.","JPN":"コホン、私はそこまで大人げなくはありませんわ。","ENG":"Ahem... I am not that childish of a person.","TWN":"咳咳，我不是那麼幼稚的人。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그런데 신기하네. 학회 사람들은 맥크레디란 이름만 들어도 벌벌 떨던 거 아니었어?","JPN":"でも不思議だね。学会の人たちってマクレディーの名を聞いただけでもビビるんじゃなかったっけ？","ENG":"But it is strange. Don't the Society members all tremble when they hear the name MacCready?","TWN":"不過好神奇啊。學會的人不是應該聽到麥克蕾蒂的名字，就瑟瑟發抖嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맥크레디라 적당한 선에서 끝난 거야.","JPN":"マクレディーだからその辺で終わったのよ。","ENG":"It was because she is a MacCready that it ended like this.","TWN":"因為是麥克蕾蒂，他們才會適可而止。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아니면 부학회장님은 지금쯤 어딘가에 갇혀서 차라리 죽여 달라고 애원하고 있을 테니까.","JPN":"そうでなかったら副学会長は今頃どこかに閉じ込められて、いっそのこと殺してくれって哀願してたはずだもの。","ENG":"If it were anyone else, that person would be locked in a cell and begging to be executed.","TWN":"不然的話，副學會長現在就該被關在某個地方，哀求著喊乾脆殺了我吧。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데, 콜록……!","JPN":"でも、ゲホッ……！","ENG":"But– *Cough!*","TWN":"可是，咳咳……！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 법학부장이란 사람이 한 말은 뭐죠?","JPN":"でも、法学部長という人の話なのですが。","ENG":"But why did that Dean of Law say that to me?","TWN":"可是法學院院長說的話，是什麼意思？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 학회장 자리에 오르면 다들 따르기라도 한다는 건가요?","JPN":"私が学会長になれば、みんなが従うとでもいうんですの？","ENG":"If I become President, then will they follow me without question?","TWN":"我當上學會長的話，大家就會服從我嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그럼. 학회 내의 누구도 맥크레디 가문 출신의 학회장을 거스르기란 불가능해.","JPN":"もちろんよ。学会内の誰であってもマクレディー家出身の学会長に逆らうことは不可能だわ。","ENG":"Of course. It is impossible for anyone within the Society to disobey a MacCready President.","TWN":"那當然。學會內的任何人都不可能違抗麥克蕾蒂家族出身的學會長。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"절 앞에 세워 놓고 좋을 대로 떠들던 사람들이 말인가요?","JPN":"私を前に自分勝手な主張をしていたあの人たちがですか？","ENG":"Even those who stood in front of me before?","TWN":"也包括那些當著我的面大放厥詞的人嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니면 설마…… 학회장이 호수를 거느리기 때문에?","JPN":"まさか……学会長が湖を従えているから？","ENG":"Could it be... that it is because the President is in charge of the Lake?","TWN":"或者……難道是因為學會長能支配湖水？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};